// Step 1: Get raw AI response
const raw = $json.output?.[0]?.content?.[0]?.text || "{}";

// Step 2: Extract JSON safely
let data = {};
try {
  const match = raw.match(/\{[\s\S]*\}/);
  data = match ? JSON.parse(match[0]) : {};
} catch (e) {
  data = {};
}

// ---------- CLEANUPS ----------

// Clean Experience
let experience = data["Experience"] || "";
if (experience) {
  const match = experience.match(/\d+\+?\s*(years?|yrs?)/i);
  experience = match ? match[0] : "";
}

// Trim long text fields
const cleanText = (text, limit = 400) => {
  if (!text) return "";
  return text.replace(/\s+/g, " ").trim().slice(0, limit);
};

// Normalize hashtags
const hashtags = data["Hashtags"] || "";
const cleanHashtags = hashtags
  .split(",")
  .map(h => h.trim())
  .filter(h => h.startsWith("#"))
  .join(", ");

// ---------- OUTPUT ----------

return [{
  json: {
    // ---- BASE ----
    "Job Search ID": $json["Job Search ID"] ?? "",
    "Raw Post": $json["Raw Post"] ?? "",
    "Post Link": $json["Post Link"] ?? "",
    "Person Name": $json["Person Name"] ?? "",
    "Person Title": $json["Person Title"] ?? "",
    "Date of Search": $json["Date of Search"] ?? new Date().toISOString().slice(0,10),

    // ---- JOB ----
    "Hiring Line": data["Hiring Line"] ?? "",
    "Job Role": data["Job Role"] ?? "",
    "Company": data["Company"] ?? "",
    "Location": data["Location"] ?? "",
    "Salary": data["Salary"] ?? "",
    "Experience": experience,

    // ---- CONTENT ----
    "Responsibilities": cleanText(data["Responsibilities"], 500),
    "Skills Required": cleanText(data["Skills Required"], 300),

    // ---- CONTACT ----
    "Apply Link": data["Apply Link"] || $json["Apply Link"] || "",
    "Apply Email": data["Apply Email"] || $json["Email in Post"] || "",

    // ---- META ----
    "Hashtags": cleanHashtags,
    "Domain": data["Domain"] ?? "",
  }
}];

const now = new Date();

// Format: YYYYMMDDHHMMSS
const timestamp = now.toISOString().replace(/[-:TZ.]/g, "").slice(0,14);

// Random 4 digit
const random = Math.floor(1000 + Math.random() * 9000);

// Final ID
const jobId = `JS-${timestamp}-${random}`;

return [{
  json: {
    "Job Search ID": jobId,
    "Raw Post": $json["Raw Post"] || "",
    "Post Link": $json["Post Link"] || ""
  }
}];

const text = $json["Raw Post"] || "";

// ---------------- CLEAN LINES ----------------
const lines = text
  .split("\n")
  .map(l => l.trim())
  .filter(l => l.length > 0);

// ---------------- EMAIL ----------------
const emailMatch = text.match(/[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+\.[a-z]{2,}/);
const email = emailMatch ? emailMatch[0] : "";

// ---------------- APPLY LINK ----------------
const linkMatch = text.match(/https?:\/\/[^\s]+/);
const applyLink = linkMatch ? linkMatch[0] : "";

// ---------------- NAME ----------------
let name = "";

const nameMatch = text.match(/View\s+([A-Za-z\s\.]+)’s profile/i);

if (nameMatch) {
  name = nameMatch[1].trim();
} else {
  // fallback: strict human name pattern
  name = lines.find(l =>
    /^[A-Z][a-z]+(\s[A-Z][a-z]+)+$/.test(l)
  ) || "";
}

// ---------------- TITLE ----------------
let title = "";

if (name) {
  const noisePatterns = [
    /^•/,           // • 2nd
    /^follow$/i,
    /^\d+h/,        // 3h, 11h
    /^edited/i,
    /^connect$/i
  ];

  const nameIndex = lines.findIndex(l => l === name);

  for (let i = nameIndex + 1; i < nameIndex + 6; i++) {
    if (!lines[i]) continue;

    const isNoise = noisePatterns.some(p => p.test(lines[i]));

    if (!isNoise) {
      title = lines[i];
      break;
    }
  }
}

// ---------------- ROLE ----------------
let role = "";

const roleMatch = text.match(/Hiring[:\-]?\s*(.*)/i);
if (roleMatch) {
  role = roleMatch[1].split("|")[0].trim();
}

// ---------------- LOCATION ----------------
let location = "";
if (/bengaluru|bangalore/i.test(text)) location = "Bengaluru";

// ---------------- SALARY ----------------
const salaryMatch = text.match(/₹\s?\d+[–-]?\d*\s?(LPA|L|lakhs?)/i);
const salary = salaryMatch ? salaryMatch[0] : "";

// ---------------- OUTPUT ----------------
return [{
  json: {
    ...$json,
    "Person Name": name,
    "Person Title": title,
    "Email in Post": email,
    "Apply Link": applyLink,
    "Role": role,
    "Location": location,
    "Salary Mentioned": salary
  }
}];

// Step 1: Get raw text
const raw = $json.content?.[0]?.text || "";

// Step 2: Try extracting JSON from ```json block
let jsonText = "";

const codeBlockMatch = raw.match(/```json\s*([\s\S]*?)\s*```/);

if (codeBlockMatch) {
  jsonText = codeBlockMatch[1];
} else {
  // fallback: extract any JSON object
  const fallbackMatch = raw.match(/\{[\s\S]*\}/);
  jsonText = fallbackMatch ? fallbackMatch[0] : "{}";
}

// Step 3: Parse safely
let data = {};
try {
  data = JSON.parse(jsonText);
} catch (e) {
  data = {};
}

// Step 4: return
return [{ json: data }];;
